import React, { useState, useEffect, useRef, useCallback } from 'react';
import {
  ShoppingBag, Search, ShoppingCart, UserCircle, LogOut, X, Send,
  ChevronLeft, ChevronRight, Sparkles, Star, TrendingUp, Bot, Mic,
  RotateCcw, Package
} from 'lucide-react';
import { productsAPI } from '/home/sidhu/Desktop/ECommerceAPI/frontend/src/api.js';

// ─── Design tokens — mirrors HomePage exactly ──────────────────────
// Primary button  : bg-gradient-to-r from-teal-500 to-cyan-600
//                   hover:from-teal-600 hover:to-cyan-700
//                   shadow-md hover:shadow-cyan-200/50 active:scale-95
// Page background : bg-[#F8FAFC]
// Nav             : bg-white/80 backdrop-blur-md border-b border-gray-100
// Text            : slate-900 / slate-600 / slate-500
// Accent tints    : teal-50, cyan-50
// ──────────────────────────────────────────────────────────────────

const PRI = 'bg-gradient-to-r from-teal-500 to-cyan-600 hover:from-teal-600 hover:to-cyan-700 text-white font-semibold transition-all shadow-md hover:shadow-cyan-200/50 active:scale-95';

// ─── helpers ───────────────────────────────────────────────────────
const getCategoryName = (p) => {
  if (!p) return 'Uncategorized';
  const c = p.categoryName || p.category;
  if (!c) return 'Uncategorized';
  if (typeof c === 'string') return c;
  if (typeof c === 'object' && c.name) return c.name;
  return String(c);
};
const getPrice = (p) => {
  if (!p?.price) return 0;
  if (typeof p.price === 'number') return p.price;
  if (p.price?.$numberDecimal) return parseFloat(p.price.$numberDecimal);
  return parseFloat(p.price) || 0;
};
const getRating = (p) => {
  if (!p?.rating) return null;
  if (typeof p.rating === 'number') return p.rating;
  if (p.rating?.$numberDecimal) return parseFloat(p.rating.$numberDecimal);
  return parseFloat(p.rating) || null;
};

// ─── Chat Bot Floating Icon ────────────────────────────────────────
const ChatBotIcon = ({ onClick }) => (
  <button onClick={onClick} className="fixed bottom-8 right-8 z-50 group">
    <span className="absolute inset-0 rounded-full animate-ping opacity-60"
      style={{ background: 'radial-gradient(circle, rgba(20,184,166,0.4) 0%, transparent 70%)', width: 64, height: 64 }} />
    <div className={`relative w-16 h-16 rounded-full flex items-center justify-center group-hover:scale-110 transition-all duration-300 ${PRI}`}
      style={{ boxShadow: '0 0 0 3px rgba(20,184,166,0.2), 0 8px 32px rgba(20,184,166,0.3)' }}>
      <div className="absolute inset-0 rounded-full"
        style={{ background: 'conic-gradient(from 0deg, transparent 60%, rgba(255,255,255,0.3) 80%, transparent 100%)', animation: 'chatSpin 3s linear infinite' }} />
      <Bot className="relative z-10 w-7 h-7 text-white" strokeWidth={1.5} />
    </div>
    <span className="absolute -top-9 left-1/2 -translate-x-1/2 bg-white text-teal-700 text-xs font-black px-2.5 py-1 rounded-full shadow-lg border border-teal-100 whitespace-nowrap opacity-0 group-hover:opacity-100 transition-all">
      AI Assistant
    </span>
    <style>{`@keyframes chatSpin{from{transform:rotate(0)}to{transform:rotate(360deg)}}`}</style>
  </button>
);

// ─── Chat Widget ───────────────────────────────────────────────────
const ChatWidget = ({ onClose, products, cart, addToCart, setError }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [typing, setTyping] = useState(false);
  const [ready, setReady] = useState(false);
  const endRef = useRef(null);

  useEffect(() => { setTimeout(() => setReady(true), 10); }, []);
  useEffect(() => { endRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, typing]);

  const quickPrompts = [
    { icon: '📱', label: 'Smartphones',  q: 'Show me top smartphones' },
    { icon: '💰', label: 'Under ₹5k',    q: 'Products under 5000' },
    { icon: '⭐', label: 'Top Rated',    q: 'Best rated products' },
    { icon: '🎧', label: 'Audio',        q: 'Show audio products' },
  ];

  const sendMsg = async (text) => {
    setMessages(p => [...p, { role: 'user', content: text, t: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }]);
    setInput('');
    setTyping(true);
    await new Promise(r => setTimeout(r, 800 + Math.random() * 700));
    const lc = text.toLowerCase();
    let res = '';
    if (lc.includes('hi') || lc.includes('hello') || lc.includes('hey'))
      res = "👋 Hey there! I'm your AI shopping assistant.\n\n• 🔍 Find perfect products\n• 💸 Best deals & offers\n• 🛒 Manage your cart\n• ⭐ Personalized picks\n\nWhat are you looking for?";
    else if (lc.includes('phone') || lc.includes('smartphone') || lc.includes('mobile'))
      res = `📱 Smartphones — ${(products||[]).filter(p=>getCategoryName(p).toLowerCase().includes('phone')||getCategoryName(p).toLowerCase().includes('electronic')).length} available!\n\n🏆 Top: Samsung Galaxy S25 — ₹79,999\n⭐ 4.8/5 · Free delivery tomorrow\n\n🥈 Also: Pixel 9 Pro — ₹89,999\n\nFilter by budget or features?`;
    else if (lc.includes('budget') || lc.includes('under') || lc.includes('cheap'))
      res = `💰 Budget Picks!\n\n✅ Under ₹999: Cables, Cases, Chargers\n✅ Under ₹5,000: Earbuds, Smart Bands\n✅ Under ₹10,000: Smartphones, Tablets\n\nWhich range?`;
    else if (lc.includes('cart'))
      res = cart.length === 0
        ? "🛒 Cart is empty!\n\nWant trending picks or today's hot deals?"
        : `🛒 Cart — ${cart.length} items\n${cart.map(i=>`• ${i.name||i.productName} ×${i.quantity}`).join('\n')}\n\n💳 Total: ₹${cart.reduce((s,i)=>s+getPrice(i)*i.quantity,0).toLocaleString()}\n\nReady to checkout?`;
    else if (lc.includes('deal') || lc.includes('offer') || lc.includes('sale'))
      res = "🔥 Live Deals Today!\n\n⚡ Flash Sale:\n• Electronics: Up to 50% OFF\n• Audio: Buy 1 Get 1 Free\n\n🎁 Coupons:\n• SAVE10 — 10% off\n• FIRST50 — 50% first order\n• TECH200 — ₹200 off ₹2000+";
    else if (lc.includes('deliver') || lc.includes('shipping') || lc.includes('track'))
      res = "🚚 Delivery Info:\n\n• Express: Tomorrow by 10 AM ⚡\n• Standard: 2–4 business days\n• Free shipping on ₹999+\n\n📦 Track: Profile → My Orders → Track";
    else if (lc.includes('recommend') || lc.includes('suggest') || lc.includes('best'))
      res = "✨ Trending Now:\n\n🥇 Premium Smartphone X1 — ₹9,999\n🥈 Wireless Earbuds Pro — ₹2,499\n🥉 Smart Watch Ultra — ₹4,999\n\n🔥 Sony WH-1000XM5 — 30% OFF tonight!";
    else
      res = "🤔 I can help with:\n\n🔍 Find products — \"gaming laptop\"\n💰 Budget — \"headphones under ₹2000\"\n🛒 Cart — \"show my cart\"\n🏷️ Deals — \"today's offers\"";
    setMessages(p => [...p, { role: 'assistant', content: res, t: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }]);
    setTyping(false);
  };

  return (
    <div className="fixed bottom-8 right-8 z-50 w-[390px] rounded-3xl overflow-hidden flex flex-col bg-white"
      style={{
        height: 600,
        boxShadow: '0 32px 80px rgba(0,0,0,0.15), 0 0 0 1px rgba(20,184,166,0.15)',
        transform: ready ? 'scale(1) translateY(0)' : 'scale(0.9) translateY(20px)',
        opacity: ready ? 1 : 0,
        transformOrigin: 'bottom right',
        transition: 'all 0.35s cubic-bezier(0.34,1.56,0.64,1)',
      }}>
      <style>{`
        @keyframes chatSpin{from{transform:rotate(0)}to{transform:rotate(360deg)}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
        @keyframes dotBounce{0%,60%,100%{transform:translateY(0);opacity:.4}30%{transform:translateY(-5px);opacity:1}}
        @keyframes onlinePulse{0%,100%{opacity:1}50%{opacity:.4}}
      `}</style>

      {/* Header — same gradient as primary button */}
      <div className="relative flex items-center justify-between px-5 py-4 shrink-0 bg-gradient-to-r from-teal-500 to-cyan-600">
        {/* decorative rings */}
        <div className="absolute inset-0 overflow-hidden opacity-10 pointer-events-none">
          {[...Array(4)].map((_,i) => (
            <div key={i} className="absolute rounded-full border-2 border-white"
              style={{ width:50+i*40, height:50+i*40, top:-14+i*5, right:-14+i*5, animation:`chatSpin ${4+i}s linear infinite` }} />
          ))}
        </div>
        <div className="flex items-center gap-3 relative z-10">
          <div className="w-11 h-11 rounded-2xl flex items-center justify-center relative" style={{ background:'rgba(255,255,255,0.2)', border:'1px solid rgba(255,255,255,0.3)' }}>
            <Bot className="w-6 h-6 text-white" strokeWidth={1.5} />
            <span className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-emerald-400 rounded-full border-2 border-teal-500"
              style={{ animation:'onlinePulse 2s infinite' }} />
          </div>
          <div>
            <div className="flex items-center gap-2">
              <h3 className="font-black text-white text-sm">ShopAI Assistant</h3>
              <span className="text-[10px] bg-white/25 text-white px-1.5 py-0.5 rounded-full font-bold">AI</span>
            </div>
            <p className="text-teal-100 text-xs flex items-center gap-1.5 mt-0.5">
              <span className="w-1.5 h-1.5 bg-emerald-300 rounded-full" style={{ animation:'onlinePulse 2s infinite' }} />
              Online · Replies instantly
            </p>
          </div>
        </div>
        <div className="flex gap-1 relative z-10">
          <button onClick={() => setMessages([])} className="w-8 h-8 flex items-center justify-center rounded-xl text-white/70 hover:text-white hover:bg-white/15 transition-all">
            <RotateCcw className="w-3.5 h-3.5" />
          </button>
          <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-xl text-white/70 hover:text-white hover:bg-white/15 transition-all">
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Messages area */}
      <div className="flex-1 overflow-y-auto px-4 py-4 space-y-3 bg-[#F8FAFC]"
        style={{ scrollbarWidth:'thin', scrollbarColor:'rgba(20,184,166,0.2) transparent' }}>

        {messages.length === 0 && (
          <div className="flex flex-col items-center text-center pt-5 pb-2" style={{ animation:'fadeUp .5s ease both' }}>
            <div className="w-16 h-16 rounded-3xl flex items-center justify-center mb-3 bg-teal-50 border border-teal-100">
              <Sparkles className="w-8 h-8 text-teal-500" />
            </div>
            <h4 className="text-slate-900 font-black text-base mb-1">Hello, Shopper! 👋</h4>
            <p className="text-slate-500 text-xs mb-5 leading-relaxed max-w-[240px]">Your AI shopping assistant. Ask about products, deals, or your cart!</p>
            <div className="grid grid-cols-2 gap-2 w-full">
              {quickPrompts.map((qp, i) => (
                <button key={i} onClick={() => sendMsg(qp.q)}
                  className="flex items-center gap-2 px-3 py-2.5 rounded-2xl text-left bg-white border border-gray-100 hover:border-teal-200 hover:bg-teal-50 transition-all hover:scale-[1.02] group"
                  style={{ animation:`fadeUp .5s ease ${i*0.08}s both` }}>
                  <span className="text-base">{qp.icon}</span>
                  <span className="text-xs font-bold text-slate-700 group-hover:text-teal-700">{qp.label}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex gap-2 ${msg.role==='user'?'justify-end':'justify-start'}`}
            style={{ animation:'fadeUp .3s ease both' }}>
            {msg.role === 'assistant' && (
              <div className="w-7 h-7 rounded-xl flex items-center justify-center shrink-0 mt-auto bg-gradient-to-br from-teal-500 to-cyan-600">
                <Bot className="w-4 h-4 text-white" strokeWidth={1.5} />
              </div>
            )}
            <div className="max-w-[78%] flex flex-col gap-0.5">
              <div className="px-3.5 py-2.5 text-sm leading-relaxed"
                style={msg.role==='user' ? {
                  background:'linear-gradient(135deg, #14b8a6, #0891b2)',
                  color:'white', borderRadius:'18px 18px 4px 18px',
                  boxShadow:'0 4px 14px rgba(20,184,166,0.25)',
                } : {
                  background:'white', border:'1px solid #e2e8f0',
                  color:'#0f172a', borderRadius:'4px 18px 18px 18px',
                  whiteSpace:'pre-line', boxShadow:'0 1px 4px rgba(0,0,0,0.05)',
                }}>
                {msg.content}
              </div>
              <span className="text-[10px] text-slate-400 px-1">{msg.t}</span>
            </div>
          </div>
        ))}

        {typing && (
          <div className="flex items-end gap-2" style={{ animation:'fadeUp .3s ease both' }}>
            <div className="w-7 h-7 rounded-xl flex items-center justify-center shrink-0 bg-gradient-to-br from-teal-500 to-cyan-600">
              <Bot className="w-4 h-4 text-white" strokeWidth={1.5} />
            </div>
            <div className="px-4 py-3 bg-white border border-gray-100 flex gap-1 shadow-sm" style={{ borderRadius:'4px 18px 18px 18px' }}>
              {[0,1,2].map(j => <div key={j} className="w-2 h-2 bg-teal-400 rounded-full" style={{ animation:`dotBounce 1.2s ease ${j*.2}s infinite` }} />)}
            </div>
          </div>
        )}
        <div ref={endRef} />
      </div>

      {/* Quick chips */}
      {messages.length > 0 && messages.length < 4 && (
        <div className="flex gap-2 px-4 py-2 bg-white border-t border-gray-50 overflow-x-auto" style={{ scrollbarWidth:'none' }}>
          {['🔥 Hot deals','📦 Track order','🏷️ Coupons'].map((c,i) => (
            <button key={i} onClick={() => sendMsg(c.replace(/[^\w\s]/g,'').trim())}
              className="shrink-0 text-xs px-3 py-1.5 rounded-full bg-teal-50 border border-teal-100 text-teal-700 font-bold hover:bg-teal-100 transition-all whitespace-nowrap">
              {c}
            </button>
          ))}
        </div>
      )}

      {/* Input */}
      <div className="px-4 py-3 bg-white border-t border-gray-100 shrink-0">
        <div className="flex items-end gap-2 px-3 py-2 rounded-2xl bg-slate-50 border border-gray-200 focus-within:border-teal-300 focus-within:shadow-md focus-within:shadow-teal-50 transition-all">
          <textarea value={input} onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key==='Enter' && !e.shiftKey) { e.preventDefault(); if (input.trim() && !typing) sendMsg(input.trim()); }}}
            placeholder="Ask me anything..." rows={1} disabled={typing}
            className="flex-1 bg-transparent text-slate-800 placeholder-slate-400 text-sm resize-none focus:outline-none leading-5 py-1 max-h-28"
            style={{ scrollbarWidth:'none' }} />
          <div className="flex items-center gap-1">
            <button className="w-8 h-8 flex items-center justify-center rounded-xl text-slate-400 hover:text-teal-500 transition-colors">
              <Mic className="w-4 h-4" />
            </button>
            <button onClick={() => { if (input.trim() && !typing) sendMsg(input.trim()); }}
              disabled={!input.trim() || typing}
              className={`w-9 h-9 flex items-center justify-center rounded-xl transition-all active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed ${input.trim() ? `${PRI} !rounded-xl` : 'bg-gray-100'}`}>
              <Send className="w-4 h-4 text-white" />
            </button>
          </div>
        </div>
        <p className="text-center text-[10px] text-slate-400 mt-2">Powered by ShopAI · AI may not always be accurate</p>
      </div>
    </div>
  );
};

// ─── Product Card ──────────────────────────────────────────────────
const ProductCard = ({ product, addToCart, setError }) => {
  const [hovered, setHovered] = useState(false);
  const [added, setAdded] = useState(false);
  const price = getPrice(product);
  const rating = getRating(product);
  const category = getCategoryName(product);

  const handleAdd = () => {
    addToCart(product, setError);
    setAdded(true);
    setTimeout(() => setAdded(false), 1200);
  };

  return (
    <div onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
      className="bg-white rounded-3xl overflow-hidden flex flex-col transition-all duration-300 group"
      style={{
        border: hovered ? '1px solid rgba(20,184,166,0.3)' : '1px solid #f1f5f9',
        boxShadow: hovered ? '0 20px 50px rgba(20,184,166,0.12), 0 4px 16px rgba(0,0,0,0.06)' : '0 1px 6px rgba(0,0,0,0.04)',
        transform: hovered ? 'translateY(-4px)' : 'translateY(0)',
      }}>
      {/* Image */}
      <div className="relative overflow-hidden bg-slate-50" style={{ paddingBottom:'100%' }}>
        <img
          src={product.imageUrl || `https://via.placeholder.com/300x300/f0fdfa/14b8a6?text=${encodeURIComponent((product.name||'').slice(0,8))}`}
          alt={product.name}
          className="absolute inset-0 w-full h-full object-contain p-3 transition-transform duration-400"
          style={{ transform: hovered ? 'scale(1.07)' : 'scale(1)' }}
          onError={e => { e.currentTarget.src = 'https://via.placeholder.com/300x300/f0fdfa/14b8a6?text=Product'; }}
        />
        <div className="absolute top-2.5 left-2.5 flex flex-col gap-1">
          <span className="text-[10px] font-black text-white px-2 py-0.5 rounded-full bg-gradient-to-r from-orange-400 to-orange-500">-20%</span>
          {product.stockQuantity !== undefined && product.stockQuantity <= 5 && product.stockQuantity > 0 && (
            <span className="text-[10px] font-bold text-white px-2 py-0.5 rounded-full bg-amber-500">Only {product.stockQuantity} left</span>
          )}
        </div>
        {product.score && (
          <span className={`absolute top-2.5 right-2.5 text-[10px] font-black text-white px-2 py-0.5 rounded-full ${PRI} !rounded-full !py-0.5 !px-2 !shadow-none`}>
            {Math.round(product.score*100)}%
          </span>
        )}
        <div className="absolute inset-0 flex items-center justify-center transition-all duration-200"
          style={{ background:'rgba(15,23,42,0.35)', opacity: hovered?1:0, backdropFilter: hovered?'blur(2px)':'none' }}>
          <button onClick={() => alert(`${product.name}\n\n₹${price.toLocaleString()}\n${product.description||''}`)}
            className="px-4 py-2 bg-white text-slate-900 text-xs font-black rounded-full shadow-lg hover:scale-105 active:scale-95 transition-all">
            Quick View
          </button>
        </div>
      </div>

      {/* Info */}
      <div className="p-4 flex flex-col flex-1">
        <p className="text-[10px] font-black text-teal-600 uppercase tracking-widest mb-1">{product.brand || category}</p>
        <h3 className="text-sm font-bold text-slate-900 mb-2 line-clamp-2 leading-snug">{product.name}</h3>
        {rating && (
          <div className="flex items-center gap-1 mb-2">
            {[...Array(5)].map((_,i) => (
              <Star key={i} className="w-3 h-3" fill={i<Math.floor(rating)?'#f59e0b':'none'} stroke={i<Math.floor(rating)?'#f59e0b':'#d1d5db'} />
            ))}
            <span className="text-[10px] text-slate-400 ml-0.5">({product.reviewCount||0})</span>
          </div>
        )}
        <div className="mt-auto mb-3">
          <div className="flex items-baseline gap-1.5">
            <span className="text-lg font-black text-slate-900">₹{price.toLocaleString()}</span>
          </div>
          <div className="flex items-center gap-2 mt-0.5">
            <span className="text-xs text-slate-400 line-through">₹{(price*1.2).toLocaleString(undefined,{maximumFractionDigits:0})}</span>
            <span className="text-[10px] font-bold text-emerald-600">Save ₹{(price*0.2).toLocaleString(undefined,{maximumFractionDigits:0})}</span>
          </div>
        </div>
        <button onClick={handleAdd} disabled={product.stockQuantity===0}
          className={`w-full py-2.5 text-sm font-bold rounded-2xl transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${added?'bg-gradient-to-r from-emerald-500 to-green-600 text-white shadow-md':PRI}`}>
          {product.stockQuantity===0?'Out of Stock':added?'✓ Added!':'Add to Cart'}
        </button>
      </div>
    </div>
  );
};

// ─── Main Page ─────────────────────────────────────────────────────
const ProductsPage = ({ user, products, cart, searchQuery, setSearchQuery, setCurrentPage, handleLogout, addToCart, error, setError }) => {
  const [chatOpen, setChatOpen] = useState(false);
  const [banner, setBanner] = useState(0);
  const [suggestions, setSuggestions] = useState([]);
  const [showSug, setShowSug] = useState(false);
  const [semanticResults, setSemanticResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [semanticMode, setSemanticMode] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const debounce = useRef(null);

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', fn);
    return () => window.removeEventListener('scroll', fn);
  }, []);
  useEffect(() => {
    const t = setInterval(() => setBanner(p => (p+1)%3), 5000);
    return () => clearInterval(t);
  }, []);
  useEffect(() => {
    const q = searchQuery.trim();
    if (!q || q.length < 2) { setSuggestions([]); setShowSug(false); if (!q) { setSemanticMode(false); setSemanticResults([]); } return; }
    clearTimeout(debounce.current);
    debounce.current = setTimeout(async () => {
      setLoading(true);
      try { const r = await productsAPI.search(q, 6); const d = r?.data?.results||[]; setSuggestions(d); setShowSug(d.length>0); }
      catch { setSuggestions([]); } finally { setLoading(false); }
    }, 300);
    return () => clearTimeout(debounce.current);
  }, [searchQuery]);

  const doSearch = useCallback(async (override) => {
    const q = (override || searchQuery).trim();
    if (!q) return;
    setShowSug(false); setLoading(true); setSemanticMode(true);
    try { const r = await productsAPI.search(q, 20); setSemanticResults(r?.data?.results||[]); }
    catch { setSemanticResults([]); setError('Search failed.'); setSemanticMode(false); }
    finally { setLoading(false); }
  }, [searchQuery]);

  const clearSearch = () => { setSearchQuery(''); setSemanticMode(false); setSemanticResults([]); };
  const applyCategory = async (cat) => { if (!cat) { clearSearch(); return; } setSearchQuery(cat); await doSearch(cat); };

  const displayed = semanticMode ? semanticResults : (products||[]);
  const categories = Array.from(new Set((products||[]).map(p=>getCategoryName(p)).filter(Boolean))).slice(0,20);

  const banners = [
    { title:'Summer Sale 2026', sub:'Up to 50% OFF on Electronics', desc:'Free shipping on orders above ₹999', tag:'🔥 LIMITED TIME', from:'from-teal-500', to:'to-cyan-600' },
    { title:'New Arrivals', sub:'Latest Smartphones & Gadgets', desc:'Shop the newest tech at best prices', tag:'✨ JUST IN', from:'from-violet-500', to:'to-purple-600' },
    { title:'Special Offer', sub:'Buy 2 Get 1 Free', desc:'On selected audio & wearables', tag:'🎁 EXCLUSIVE', from:'from-orange-400', to:'to-rose-500' },
  ];

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans selection:bg-teal-100 selection:text-teal-900">
      <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800;900&display=swap" rel="stylesheet" />
      <style>{`body{font-family:'Outfit',sans-serif} @keyframes fadeIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}`}</style>

      {/* ── NAV ─────────────────────────────────────────────────── */}
      <nav className={`sticky top-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/95 shadow-lg shadow-black/5' : 'bg-white/80'} backdrop-blur-md border-b border-gray-100`}>
        <div className="max-w-[1600px] mx-auto px-6">
          {/* main row */}
          <div className="h-16 flex items-center gap-4">
            {/* Logo */}
            <div className="flex items-center gap-2.5 group cursor-pointer shrink-0" onClick={clearSearch}>
              <div className="bg-gradient-to-br from-teal-500 to-cyan-600 p-2 rounded-xl group-hover:rotate-12 transition-transform duration-300">
                <ShoppingBag className="w-5 h-5 text-white" />
              </div>
              <span className="text-xl font-black bg-clip-text text-transparent bg-gradient-to-r from-teal-600 to-cyan-700 tracking-tight">ShopAI</span>
            </div>

            {/* Category dropdown */}
            <select onChange={e => applyCategory(e.target.value)}
              className="hidden md:block text-sm text-slate-700 font-semibold px-3 py-2 rounded-xl border border-gray-200 bg-white focus:outline-none focus:ring-2 focus:ring-teal-300 shrink-0"
              style={{ maxWidth:140 }}>
              <option value="">All Categories</option>
              {categories.map((c,i) => <option key={i} value={c}>{c}</option>)}
            </select>

            {/* Search bar */}
            <div className="flex-1 max-w-2xl relative">
              <div className={`flex items-center rounded-2xl border bg-white transition-all ${loading?'border-teal-300':'border-gray-200 hover:border-teal-200'} focus-within:border-teal-400 focus-within:shadow-lg focus-within:shadow-teal-100/40`}>
                <Search className="w-4 h-4 text-teal-500 ml-4 shrink-0" />
                <input value={searchQuery}
                  onChange={e => { setSearchQuery(e.target.value); if (!e.target.value.trim()) clearSearch(); }}
                  onKeyDown={e => { if (e.key==='Enter') doSearch(); if (e.key==='Escape') setShowSug(false); }}
                  onBlur={() => setTimeout(() => setShowSug(false), 200)}
                  onFocus={() => suggestions.length > 0 && setShowSug(true)}
                  placeholder="Search with AI — try 'wireless earbuds under ₹2000'..."
                  className="flex-1 bg-transparent text-slate-900 placeholder-slate-400 px-3 py-3 text-sm focus:outline-none" />
                {loading
                  ? <div className="w-4 h-4 border-2 border-teal-500 border-t-transparent rounded-full animate-spin mr-3" />
                  : <button onClick={() => doSearch()}
                      className="flex items-center gap-1.5 px-4 py-3 text-sm font-bold text-teal-600 hover:bg-teal-50 transition-all border-l border-gray-100 rounded-r-2xl">
                      <Sparkles className="w-4 h-4" />
                      <span className="hidden lg:block">AI Search</span>
                    </button>
                }
              </div>

              {showSug && suggestions.length > 0 && (
                <div className="absolute top-full left-0 right-0 mt-2 rounded-2xl overflow-hidden z-50 bg-white border border-gray-100 shadow-2xl shadow-black/10">
                  <div className="px-4 py-2.5 flex items-center gap-2 bg-teal-50 border-b border-teal-100">
                    <Sparkles className="w-3.5 h-3.5 text-teal-500" />
                    <span className="text-xs font-black text-teal-700 uppercase tracking-wider">AI Suggestions</span>
                  </div>
                  {suggestions.map((item,idx) => (
                    <div key={item.id||item._id||idx}
                      onMouseDown={() => { setSearchQuery(item.name); setShowSug(false); doSearch(item.name); }}
                      className="px-4 py-3 cursor-pointer flex items-center justify-between gap-4 hover:bg-teal-50 transition-colors border-b border-gray-50 last:border-0">
                      <div className="flex-1 min-w-0">
                        <p className="text-sm text-slate-900 font-semibold truncate">{item.name}</p>
                        <p className="text-xs text-slate-400">{item.brand||getCategoryName(item)}</p>
                      </div>
                      <div className="shrink-0 text-right">
                        <p className="text-sm font-black text-teal-600">₹{getPrice(item).toLocaleString()}</p>
                        {item.score && <p className="text-[10px] text-slate-400">{Math.round(item.score*100)}% match</p>}
                      </div>
                    </div>
                  ))}
                  <div onMouseDown={() => { setShowSug(false); doSearch(); }}
                    className="px-4 py-2.5 text-center text-sm text-teal-600 font-bold hover:bg-teal-50 cursor-pointer border-t border-gray-100">
                    See all results for "{searchQuery}" →
                  </div>
                </div>
              )}
            </div>

            {/* Right side */}
            <div className="flex items-center gap-2 shrink-0">
              <button onClick={() => setCurrentPage('profile')}
                className="hidden sm:flex items-center gap-2 px-3 py-2 rounded-xl text-sm font-bold text-slate-600 hover:text-teal-600 hover:bg-teal-50 transition-all">
                <UserCircle className="w-5 h-5" />
                <span className="hidden lg:block">{user?.name?.split(' ')[0]||'Account'}</span>
              </button>
              <button onClick={() => setCurrentPage('cart')}
                className={`${PRI} flex items-center gap-2 px-4 py-2.5 rounded-xl relative`}>
                <ShoppingCart className="w-5 h-5" />
                <span className="hidden lg:block text-sm">Cart</span>
                {cart.length > 0 && (
                  <span className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-orange-500 text-white text-[10px] font-black rounded-full flex items-center justify-center shadow-md">
                    {cart.length}
                  </span>
                )}
              </button>
            </div>
          </div>

          {/* Category nav strip */}
          <div className="flex items-center gap-1 pb-2.5 overflow-x-auto" style={{ scrollbarWidth:'none' }}>
            <button onClick={() => applyCategory('')}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-600 hover:text-teal-600 hover:bg-teal-50 transition-all whitespace-nowrap">
              <TrendingUp className="w-3.5 h-3.5" /> All
            </button>
            {categories.slice(0,9).map((cat,i) => (
              <button key={i} onClick={() => applyCategory(cat)}
                className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all whitespace-nowrap ${searchQuery===cat?'bg-gradient-to-r from-teal-500 to-cyan-600 text-white shadow-sm shadow-teal-200':'text-slate-500 hover:text-teal-600 hover:bg-teal-50'}`}>
                {cat}
              </button>
            ))}
            <div className="flex-1" />
            <button onClick={() => setChatOpen(c=>!c)}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold text-teal-600 hover:bg-teal-50 transition-all whitespace-nowrap">
              <Bot className="w-3.5 h-3.5" /> AI Help
            </button>
            <button onClick={handleLogout}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-slate-700 hover:bg-slate-100 transition-all whitespace-nowrap">
              <LogOut className="w-3.5 h-3.5" /> Logout
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile search */}
      <div className="md:hidden bg-white border-b border-gray-100 px-4 py-3">
        <div className="flex items-center gap-2 bg-slate-100 rounded-2xl px-3 py-2.5">
          <Search className="w-4 h-4 text-slate-400" />
          <input value={searchQuery}
            onChange={e => { setSearchQuery(e.target.value); if (!e.target.value.trim()) clearSearch(); }}
            onKeyDown={e => e.key==='Enter' && doSearch()}
            placeholder="AI-powered search..."
            className="flex-1 bg-transparent text-sm text-slate-800 focus:outline-none" />
        </div>
      </div>

      <div className="max-w-[1600px] mx-auto px-4 md:px-6">
        {error && (
          <div className="mt-4 bg-red-50 border-l-4 border-red-400 text-red-700 px-4 py-3 rounded-r-2xl text-sm font-medium">{error}</div>
        )}

        {/* ── Banner Carousel ───────────────────────────────────── */}
        <div className="relative mt-6 mb-6 rounded-[32px] overflow-hidden" style={{ height:340 }}>
          {banners.map((b,idx) => (
            <div key={idx} className={`absolute inset-0 bg-gradient-to-r ${b.from} ${b.to} transition-all duration-700`}
              style={{ opacity: banner===idx?1:0, transform: banner===idx?'scale(1)':'scale(1.02)' }}>
              {/* subtle grid */}
              <div className="absolute inset-0 opacity-[0.07]"
                style={{ backgroundImage:'linear-gradient(rgba(255,255,255,.6) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.6) 1px,transparent 1px)', backgroundSize:'48px 48px' }} />
              {/* glow orb */}
              <div className="absolute right-16 top-1/2 -translate-y-1/2 w-72 h-72 rounded-full opacity-20" style={{ background:'white', filter:'blur(60px)' }} />
              <div className="relative h-full flex flex-col justify-center px-10 md:px-14 max-w-lg">
                <span className="inline-flex items-center gap-2 text-xs font-black px-3 py-1 rounded-full mb-4 w-fit bg-white/20 text-white border border-white/30">{b.tag}</span>
                <h2 className="text-4xl md:text-5xl font-black text-white mb-2 leading-tight">{b.title}</h2>
                <p className="text-lg font-semibold text-white/90 mb-1">{b.sub}</p>
                <p className="text-white/70 text-sm mb-7">{b.desc}</p>
                <button onClick={clearSearch}
                  className="w-fit flex items-center gap-2 px-7 py-3 bg-white font-black text-sm rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl text-teal-700">
                  Shop Now →
                </button>
              </div>
            </div>
          ))}
          <button onClick={() => setBanner(p=>(p-1+3)%3)}
            className="absolute left-4 top-1/2 -translate-y-1/2 w-10 h-10 bg-white/90 hover:bg-white rounded-full flex items-center justify-center shadow-lg transition-all">
            <ChevronLeft className="w-5 h-5 text-slate-900" />
          </button>
          <button onClick={() => setBanner(p=>(p+1)%3)}
            className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 bg-white/90 hover:bg-white rounded-full flex items-center justify-center shadow-lg transition-all">
            <ChevronRight className="w-5 h-5 text-slate-900" />
          </button>
          <div className="absolute bottom-5 left-1/2 -translate-x-1/2 flex gap-2">
            {banners.map((_,i) => (
              <button key={i} onClick={() => setBanner(i)}
                className="rounded-full transition-all" style={{ width:banner===i?28:8, height:8, background:banner===i?'white':'rgba(255,255,255,0.45)' }} />
            ))}
          </div>
        </div>

        {/* ── Category Cards ────────────────────────────────────── */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
          {[
            { title:'Trending Electronics', subs:['Smartphones','Laptops','Tablets','Accessories'], cat:'Electronics', bg:'from-teal-50 to-cyan-50', border:'border-teal-100', accent:'text-teal-600' },
            { title:'Audio & Wearables',    subs:['Headphones','Smart Watches','Earbuds','Speakers'], cat:'Audio', bg:'from-violet-50 to-purple-50', border:'border-violet-100', accent:'text-violet-600' },
            { title:'Home Appliances',      subs:['Air Purifiers','Vacuum','Microwaves','Washers'], cat:'Appliances', bg:'from-orange-50 to-amber-50', border:'border-orange-100', accent:'text-orange-600' },
            { title:'Deals Under ₹999',     subs:['Cables','Cases','Chargers','More'], cat:'', bg:'from-emerald-50 to-green-50', border:'border-emerald-100', accent:'text-emerald-600' },
          ].map((c,i) => (
            <div key={i} onClick={() => applyCategory(c.cat)}
              className={`bg-gradient-to-br ${c.bg} p-5 rounded-3xl cursor-pointer border ${c.border} hover:shadow-xl hover:-translate-y-1 transition-all duration-300`}>
              <h3 className="text-sm font-black text-slate-900 mb-3">{c.title}</h3>
              <div className="grid grid-cols-2 gap-1.5 mb-3">
                {c.subs.map(s => (
                  <div key={s} className="bg-white/70 rounded-xl px-2 py-1.5">
                    <p className="text-[11px] text-slate-600 font-semibold">{s}</p>
                  </div>
                ))}
              </div>
              <span className={`text-xs font-black ${c.accent}`}>Explore →</span>
            </div>
          ))}
        </div>

        {/* ── Filter bar ───────────────────────────────────────── */}
        <div className="bg-white rounded-2xl px-5 py-3.5 mb-5 flex flex-col md:flex-row items-start md:items-center justify-between gap-3 border border-gray-100 shadow-sm">
          <div className="flex items-center gap-3">
            <span className="text-sm font-bold text-slate-700">Sort by:</span>
            <select className="text-sm border border-gray-200 rounded-xl px-3 py-1.5 bg-white focus:outline-none focus:ring-2 focus:ring-teal-300 text-slate-700">
              <option>Featured</option><option>Price: Low to High</option><option>Price: High to Low</option><option>Top Rated</option>
            </select>
          </div>
          <div className="flex items-center gap-3">
            {semanticMode && (
              <>
                <span className="text-xs font-bold px-3 py-1.5 rounded-full flex items-center gap-1.5 bg-teal-50 text-teal-700 border border-teal-100">
                  <Sparkles className="w-3 h-3" /> AI: "{searchQuery}"
                </span>
                <button onClick={clearSearch} className="text-xs text-slate-400 hover:text-slate-700 flex items-center gap-1 transition-colors font-medium">
                  <X className="w-3 h-3" /> Clear
                </button>
              </>
            )}
            <span className="text-sm text-slate-500"><span className="font-black text-slate-900">{displayed.length}</span> products</span>
          </div>
        </div>

        {/* ── Product Grid ─────────────────────────────────────── */}
        <div className="pb-12">
          {loading && semanticMode ? (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
              {[...Array(10)].map((_,i) => (
                <div key={i} className="bg-white rounded-3xl border border-gray-100 p-4 animate-pulse">
                  <div className="aspect-square bg-slate-100 rounded-2xl mb-3" />
                  <div className="h-3 bg-slate-100 rounded-full mb-2" />
                  <div className="h-3 bg-slate-100 rounded-full w-2/3 mb-3" />
                  <div className="h-10 bg-slate-100 rounded-2xl" />
                </div>
              ))}
            </div>
          ) : displayed.length === 0 ? (
            <div className="bg-white rounded-3xl p-16 text-center border border-gray-100">
              <div className="w-20 h-20 bg-teal-50 rounded-3xl flex items-center justify-center mx-auto mb-5">
                <Search className="w-9 h-9 text-teal-300" />
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2">No products found</h3>
              <p className="text-slate-500 text-sm mb-7">{semanticMode ? `No matches for "${searchQuery}"` : 'Try searching something'}</p>
              <button onClick={clearSearch} className={`${PRI} px-6 py-2.5 rounded-xl text-sm`}>View All Products</button>
            </div>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
              {displayed.map((p,i) => (
                <ProductCard key={p.id||p._id?.$oid||p._id||i} product={p} addToCart={addToCart} setError={setError} />
              ))}
            </div>
          )}
        </div>
      </div>

      {/* ── Chat ─────────────────────────────────────────────────── */}
      {chatOpen
        ? <ChatWidget onClose={() => setChatOpen(false)} products={products} cart={cart} addToCart={addToCart} setError={setError} />
        : <ChatBotIcon onClick={() => setChatOpen(true)} />
      }
    </div>
  );
};

export default ProductsPage;
